'use strict';

const API = 'https://jsonplaceholder.typicode.com/todos';

function assertEl(sel) {
  const el = document.querySelector(sel);
  if (!el) throw new Error(`Elemento não encontrado: ${sel}`);
  return el;
}

const elStatus = assertEl('#status');
const elSpinner = assertEl('#spinner');
const elErro = assertEl('#erro');
const btnReload = assertEl('#reload');
const elLista = assertEl('#lista');
const form = assertEl('#form');
const elTitulo = assertEl('#titulo');
const elDone = assertEl('#done');
const btnCriar = assertEl('#criar');
const btnSalvar = assertEl('#salvar');
const btnRemover = assertEl('#remover');
const elSelecionada = assertEl('#selecionada');

let state = {
  status: 'idle',
  message: '',
  fieldErrors: {},
  items: [],
  selectedId: null,
  draft: { titulo: '', done: false },
};

let currentJobId = 0;
let currentController = null;

function setState(patch) {
  state = { ...state, ...patch };
  render();
}

function limparErros() {
  for (const el of document.querySelectorAll('[data-err]')) el.textContent = '';
}

function renderErros(erros) {
  limparErros();
  for (const [k, v] of Object.entries(erros)) {
    const el = document.querySelector(`[data-err="${k}"]`);
    if (el) el.textContent = v;
  }
}

function render() {
  elStatus.textContent = state.status;
  elSpinner.style.display = state.status === 'loading' ? 'block' : 'none';
  elErro.textContent = state.status === 'error' ? String(state.message || 'erro') : '';

  const disabled = state.status === 'loading';
  btnReload.disabled = disabled;
  btnCriar.disabled = disabled;
  btnSalvar.disabled = disabled;
  btnRemover.disabled = disabled || state.selectedId === null;

  renderErros(state.fieldErrors);

  // lista
  elLista.innerHTML = '';
  for (const it of state.items) {
    const li = document.createElement('li');
    li.setAttribute('data-id', String(it.id));
    li.textContent = `${it.completed ? '✅' : '⬜'} ${it.title}`;
    if (it.id === state.selectedId) li.style.fontWeight = '700';
    elLista.appendChild(li);
  }

  // editor
  elTitulo.value = state.draft.titulo;
  elDone.checked = Boolean(state.draft.done);

  const sel = state.items.find((x) => x.id === state.selectedId) ?? null;
  elSelecionada.textContent = sel ? `Selecionada: #${sel.id}` : 'Nenhuma selecionada';
}

function normText(x) {
  return String(x ?? '').trim().replace(/\s+/g, ' ');
}

function validarTitulo(raw) {
  const t = normText(raw);
  if (t.length < 3) return { ok: false, msg: 'título deve ter 3+ caracteres' };
  return { ok: true, value: t };
}

async function fetchWithTimeout(url, options = {}, ms = 4000) {
  const controller = new AbortController();
  const id = setTimeout(() => controller.abort(), ms);
  try {
    return await fetch(url, { ...options, signal: controller.signal });
  } finally {
    clearTimeout(id);
  }
}

async function safeReadJson(res) {
  const text = await res.text().catch(() => '');
  try {
    return { ok: true, value: JSON.parse(text) };
  } catch {
    return { ok: false, msg: 'JSON inválido', raw: text };
  }
}

async function apiRequest(url, options = {}) {
  let res;
  try {
    res = await fetchWithTimeout(url, { headers: { Accept: 'application/json', ...options.headers }, ...options }, 4000);
  } catch (e) {
    if (e && e.name === 'AbortError') return { ok: false, msg: 'timeout/cancelado' };
    return { ok: false, msg: 'erro de rede' };
  }

  const parsed = await safeReadJson(res);

  if (!res.ok) {
    const msg = parsed.ok ? (parsed.value?.error?.message ?? res.statusText) : (parsed.raw || res.statusText);
    return { ok: false, status: res.status, msg: String(msg) };
  }

  if (!parsed.ok) return { ok: false, status: res.status, msg: parsed.msg };
  return { ok: true, status: res.status, data: parsed.value };
}

function selectById(id) {
  const n = Number(id);
  if (!Number.isFinite(n)) return;
  const it = state.items.find((x) => x.id === n) ?? null;
  setState({ selectedId: n, draft: { titulo: it ? it.title : '', done: it ? it.completed : false }, fieldErrors: {} });
}

function updateDraftFromInputs() {
  state = { ...state, draft: { titulo: elTitulo.value, done: elDone.checked } };
}

async function carregarLista() {
  currentJobId += 1;
  const jobId = currentJobId;
  if (currentController) currentController.abort();
  currentController = new AbortController();

  setState({ status: 'loading', message: '', fieldErrors: {} });

  const r = await apiRequest(`${API}?_limit=15`, { signal: currentController.signal });
  if (jobId !== currentJobId) return;

  if (!r.ok || !Array.isArray(r.data)) {
    return setState({ status: 'error', message: r.msg ?? 'falha ao carregar' });
  }

  setState({ status: 'success', items: r.data, message: '' });
}

async function criar() {
  updateDraftFromInputs();
  const v = validarTitulo(state.draft.titulo);
  if (!v.ok) return setState({ fieldErrors: { titulo: v.msg }, message: 'corrija o título' });

  setState({ status: 'loading', fieldErrors: {}, message: '' });

  const r = await apiRequest(API, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ title: v.value, completed: Boolean(state.draft.done), userId: 1 }),
  });

  if (!r.ok) return setState({ status: 'error', message: r.msg });

  // JSONPlaceholder devolve id simulado; adiciona na lista
  const novo = { id: r.data?.id ?? Date.now(), title: v.value, completed: Boolean(state.draft.done) };
  setState({ status: 'success', items: [novo, ...state.items], selectedId: novo.id, message: 'criado' });
  selectById(novo.id);
}

async function salvar(ev) {
  ev.preventDefault();
  if (state.selectedId === null) return;

  updateDraftFromInputs();
  const v = validarTitulo(state.draft.titulo);
  if (!v.ok) return setState({ fieldErrors: { titulo: v.msg }, message: 'corrija o título' });

  setState({ status: 'loading', fieldErrors: {}, message: '' });

  const id = state.selectedId;
  const r = await apiRequest(`${API}/${id}`, {
    method: 'PUT',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ id, title: v.value, completed: Boolean(state.draft.done), userId: 1 }),
  });

  if (!r.ok) return setState({ status: 'error', message: r.msg });

  const items = state.items.map((it) => (it.id === id ? { ...it, title: v.value, completed: Boolean(state.draft.done) } : it));
  setState({ status: 'success', items, message: 'salvo' });
}

async function remover() {
  if (state.selectedId === null) return;

  setState({ status: 'loading', message: '' });
  const id = state.selectedId;

  const r = await apiRequest(`${API}/${id}`, { method: 'DELETE' });
  if (!r.ok) return setState({ status: 'error', message: r.msg });

  const items = state.items.filter((it) => it.id !== id);
  setState({ status: 'success', items, selectedId: null, draft: { titulo: '', done: false }, message: 'removido' });
}

function wire() {
  btnReload.addEventListener('click', carregarLista);

  elLista.addEventListener('click', (e) => {
    const li = e.target.closest('li');
    if (!li) return;
    selectById(li.getAttribute('data-id'));
  });

  elTitulo.addEventListener('input', () => { updateDraftFromInputs(); render(); });
  elDone.addEventListener('change', () => { updateDraftFromInputs(); render(); });

  btnCriar.addEventListener('click', criar);
  form.addEventListener('submit', salvar);
  btnRemover.addEventListener('click', remover);
}

wire();
render();
carregarLista();
